#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int X, Y, Z;
        scanf("%d %d %d", &X, &Y, &Z);
        int credits = 4 * X + 2 * Y;
        printf("%d\n", credits);
    }
    return 0;
}

